'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useAuth } from '../../lib/auth';
import { useCart } from '../../lib/cart';
import { getUserOrders, getProducts } from '../../lib/db';
import { Order } from '../../lib/types';
import styles from './dashboard.module.css';

export default function Dashboard() {
  const { user, isAuthenticated, loading: authLoading, logout } = useAuth();
  const { addToCart, setIsCartOpen } = useCart();
  const router = useRouter();

  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.push('/');
    }
  }, [authLoading, isAuthenticated, router]);

  useEffect(() => {
    const fetchOrders = async () => {
      if (!user) return;
      setLoading(true);
      try {
        const userOrders = await getUserOrders(user.id);
        setOrders(userOrders);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchOrders();
  }, [user]);

  const handleReorder = async (order: Order) => {
    if (!order.items) return;
    try {
      // Fetch active catalog products to pass full Product info to cart
      const activeProducts = await getProducts();
      
      for (const item of order.items) {
        const prod = activeProducts.find((p) => p.id === item.product_id);
        if (prod) {
          addToCart(prod, item.quantity);
        } else {
          // Fallback if product is not in catalog but we have the info
          addToCart({
            id: item.product_id,
            name: item.product_name || 'Product',
            wholesale_price: item.wholesale_price || 0,
            stock_quantity: 9999, // default large stock for fallback
            in_stock: true,
            wholesaler_id: '',
          }, item.quantity);
        }
      }
      setIsCartOpen(true);
      router.push('/');
    } catch (err) {
      console.error(err);
      alert('Failed to reorder items');
    }
  };

  if (authLoading || !user) {
    return <div className={styles.loadingContainer}>Checking authentication...</div>;
  }

  return (
    <div className={styles.container}>
      {/* Navigation Header */}
      <header className="glass-nav">
        <div className={styles.navContainer}>
          <div className={styles.leftNav}>
            <Link href="/" className={styles.logo}>
              Stokiloo<span>.</span>
            </Link>
            <span className={styles.divider}>/</span>
            <span className={styles.pageTitle}>Buyer Dashboard</span>
          </div>

          <div className={styles.navActions}>
            <span className={styles.userEmail}>{user.email}</span>
            <Link href="/" className="btn btn-secondary">
              Back to Catalog
            </Link>
            <button className="btn btn-secondary" onClick={logout}>
              Sign Out
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className={styles.main}>
        <div className={styles.headerRow}>
          <div>
            <h1 className={styles.title}>Your Order History</h1>
            <p className={styles.subtitle}>Review past wholesale purchases and re-order in seconds.</p>
          </div>
        </div>

        {loading ? (
          <div className={styles.loader}>Fetching your order history...</div>
        ) : orders.length === 0 ? (
          <div className={styles.emptyState}>
            <h3>No past orders found</h3>
            <p>You haven&apos;t placed any orders yet. Visit the catalog to start sourcing goods.</p>
            <Link href="/" className="btn btn-primary" style={{ marginTop: '16px' }}>
              Shop Wholesale Goods
            </Link>
          </div>
        ) : (
          <div className={styles.ordersList}>
            {orders.map((order) => (
              <div key={order.id} className={styles.orderCard}>
                <div className={styles.orderHeader}>
                  <div className={styles.orderMeta}>
                    <div>
                      <span className={styles.metaLabel}>ORDER ID</span>
                      <span className={styles.metaVal}>{order.id.slice(0, 8).toUpperCase()}</span>
                    </div>
                    <div>
                      <span className={styles.metaLabel}>PLACED ON</span>
                      <span className={styles.metaVal}>
                        {new Date(order.created_at).toLocaleDateString(undefined, {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric',
                        })}
                      </span>
                    </div>
                    <div>
                      <span className={styles.metaLabel}>TOTAL COST</span>
                      <span className={styles.totalRevenue}>${order.total_revenue.toFixed(2)}</span>
                    </div>
                  </div>

                  <div className={styles.statusRow}>
                    <span
                      className={`badge ${
                        order.status === 'completed'
                          ? 'badge-success'
                          : order.status === 'pending'
                          ? 'badge-warning'
                          : 'badge-error'
                      }`}
                    >
                      {order.status.toUpperCase()}
                    </span>
                    <button className="btn btn-primary btn-secondary" onClick={() => handleReorder(order)}>
                      ⚡ 1-Click Reorder
                    </button>
                  </div>
                </div>

                <div className={styles.orderBody}>
                  <h4 className={styles.itemsTitle}>Items Summary</h4>
                  <div className={styles.itemsGrid}>
                    {order.items?.map((item) => (
                      <div key={item.id} className={styles.itemRow}>
                        <span className={styles.itemName}>{item.product_name}</span>
                        <span className={styles.itemQty}>Qty: {item.quantity}</span>
                        <span className={styles.itemPrice}>
                          ${((item.wholesale_price || 0) * item.quantity).toFixed(2)}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}
